// Pixels per minute on the 16h viewport (matches a ~420px device width):
// 16h = 960min. 16h viewport = ~420px usable → ~0.4375 px/min
// We use 0.5 px/min so 16h = 480px total timeline width — fits nicely
const PX_PER_MIN      = 0.5;            // px per minute
const SNAP_GRID_MIN   = 30;             // snap to 30-min boundaries
const VIEWPORT_H_MIN  = 16 * 60;        // 960 min visible (16h)
const FULL_DAY_MIN    = 24 * 60;        // 1440 min full track
const TIMELINE_WIDTH  = FULL_DAY_MIN * PX_PER_MIN; // 720px total track

// Viewport: show 16h (480px). Player scrolls to see rest of day.
const VIEWPORT_PX     = VIEWPORT_H_MIN * PX_PER_MIN; // 480px

