// ─────────────────────────────────────────────────────────────────────────────
// HAND GENERATION
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Build a hand of cards for this puzzle session.
 * runData.estimatedDriveHours split between driveToShipper (25%) and driveToDelivery (75%).
 * Hand always includes all required cards + 2–3 optional utility cards.
 * SDP card only if level >= 20.
 *
 * @param {object} runData
 * @param {number} level
 * @param {string} mode  'pre_departure' | 'practice'
 * @returns {Array<CardInstance>}
 */
function buildHand(runData, level, mode) {
  const totalDrive = Math.round((runData?.estimatedDriveHours || 7) * 60); // minutes
  // Split: shipper leg ≈ 25%, delivery ≈ 75% — both snapped to 30-min grid
  const shipperDrive   = Math.max(30,  Math.round(totalDrive * 0.25 / 30) * 30);
  const deliveryDrive  = Math.max(60,  Math.round(totalDrive * 0.75 / 30) * 30);

  // Required cards
  const required = [
    makeCard('preTrip',         CARD_TEMPLATES.preTrip),
    makeCard('driveToShipper',  { ...CARD_TEMPLATES.driveToShipper,  durationMinutes: shipperDrive  }),
    makeCard('loadCargo',       CARD_TEMPLATES.loadCargo),
    makeCard('driveToDelivery', { ...CARD_TEMPLATES.driveToDelivery, durationMinutes: deliveryDrive }),
    makeCard('postTrip',        CARD_TEMPLATES.postTrip),
  ];

  // Always include mandatory break (needed if total driving ≥ 8h)
  const optional = [makeCard('mandatoryBreak', CARD_TEMPLATES.mandatoryBreak)];

  // Add fuel stop always (teaches it doesn't pause window)
  optional.push(makeCard('fuelStop', CARD_TEMPLATES.fuelStop));

  // Rest period if overnight run likely (total drive + dock > 8h)
  const totalActivity = shipperDrive + deliveryDrive + 90 + 30 + 30;
  if (totalActivity > 480 || mode === 'practice') {
    optional.push(makeCard('restPeriod', CARD_TEMPLATES.restPeriod));
  }

  // Paperwork on some runs
  if (Math.random() < 0.5 || mode === 'practice') {
    optional.push(makeCard('paperwork', CARD_TEMPLATES.paperwork));
  }

  // SDP card at Level 20+
  if (level >= 20) {
    optional.push(makeCard('sdpBreak', CARD_TEMPLATES.sdpBreak));
  }

  return [...required, ...optional];
}

function makeCard(templateId, template) {
  return {
    instanceId:      `${templateId}_${Date.now()}_${Math.random().toString(36).slice(2,6)}`,
    templateId,
    label:           template.label,
    shortLabel:      template.shortLabel || template.label,
    type:            template.type,
    durationMinutes: template.durationMinutes,
    required:        template.required ?? false,
    category:        template.category,
    educational:     template.educational || null,
    isSDP:           template.isSDP || false,
    placed:          false,
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────────────────────

/** Format minutes as "Xh Ym" or "Ym" */
function fmtMin(minutes) {
  if (minutes <= 0) return '0m';
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  if (h === 0) return `${m}m`;
  if (m === 0) return `${h}h`;
  return `${h}h ${m}m`;
}

/** Format minutes as clock time "HH:MM" from midnight */
function fmtClock(minutes) {
  const h = Math.floor(minutes / 60) % 24;
  const m = minutes % 60;
  const ampm = h < 12 ? 'a' : 'p';
  const h12  = h === 0 ? 12 : h > 12 ? h - 12 : h;
  return m === 0 ? `${h12}${ampm}` : `${h12}:${String(m).padStart(2,'0')}${ampm}`;
}

/** Snap a minute value to the nearest 30-min grid */
function snapToGrid(minutes) {
  return Math.round(minutes / SNAP_GRID_MIN) * SNAP_GRID_MIN;
}

/** Convert px offset (from timeline left edge) to minutes */
function pxToMin(px) {
  return Math.round(px / PX_PER_MIN);
}

/** Convert minutes to px from timeline left */
function minToPx(min) {
  return min * PX_PER_MIN;
}

/**
 * Convert an array of PlacedCard entries to HOSRuleEngine entry format.
 * Returns entries sorted by startMinute.
 */
function placedCardsToEntries(placedCards) {
  return placedCards
    .map(pc => ({
      type:            pc.type,
      startMinute:     pc.startMinute,
      durationMinutes: pc.durationMinutes,
      label:           pc.label,
    }))
    .sort((a, b) => a.startMinute - b.startMinute);
}

/**
 * Compute the current shift start minute from placed entries.
 * The shift starts at the first on-duty entry.
 */
function getShiftStartMinute(placedCards) {
  const onDutyCards = placedCards.filter(
    pc => pc.type === TYPE.DRIVING || pc.type === TYPE.ON_DUTY_NOT_DRIVING
  );
  if (onDutyCards.length === 0) return null;
  return Math.min(...onDutyCards.map(pc => pc.startMinute));
}

