// ─────────────────────────────────────────────────────────────────────────────
// PRACTICE RECORD (localStorage — practice mode only)
// ─────────────────────────────────────────────────────────────────────────────

const PRACTICE_KEY = 'btb_hos_practice_best';

function getPracticeBest() {
  try { return parseInt(localStorage.getItem(PRACTICE_KEY) || '0', 10) || 0; }
  catch { return 0; }
}
function savePracticeBest(seconds) {
  try {
    const prev = getPracticeBest();
    if (seconds > 0 && (prev === 0 || seconds < prev)) {
      localStorage.setItem(PRACTICE_KEY, String(seconds));
      return true;
    }
    return false;
  } catch { return false; }
}

// ─────────────────────────────────────────────────────────────────────────────
// ENGINE ENTRY BUILDER
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Build the entry list passed to HOSRuleEngine for validation / remaining hours.
 *
 * HOSRuleEngine needs a qualifying ≥10h prior rest to anchor the 14-hour window.
 * When hosHistory is empty (practice mode) or has no single ≥10h OFF_DUTY/SB
 * entry, inject a synthetic prior rest ending at midnight (minute 0) so the
 * window constraint is always enforced in the puzzle.
 *
 * If hosHistory already contains a qualifying rest, it is used as-is — the
 * synthetic rest at minute 0 is older and the engine always uses the MOST
 * RECENT qualifying rest (so the real history takes precedence).
 *
 * Note: this checks single-entry rests only. Contiguous-block rests from
 * real hosHistory still pass through; the engine handles block detection.
 */
function buildEngineEntries(hosHistory, entries) {
  const combined = [...hosHistory, ...entries];
  const hasRest  = combined.some(
    e => (e.type === TYPE.OFF_DUTY || e.type === TYPE.SLEEPER_BERTH)
         && (e.durationMinutes || 0) >= R.PRIOR_REST_MIN
  );
  if (hasRest) return combined;
  // Inject synthetic prior rest ending at midnight (minute 0)
  return [
    {
      type:            TYPE.OFF_DUTY,
      startMinute:     -R.PRIOR_REST_MIN,  // -600 (10h before midnight)
      durationMinutes: R.PRIOR_REST_MIN,   //  600 min = 10h
      label:           '(prior rest — inferred)',
    },
    ...combined,
  ];
}

// ─────────────────────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────────────────────

const HOSPuzzle = memo(function HOSPuzzle({
  // Required
  onComplete,
  onClose,
  // Route context
  runData = {
    originCity:          'Chicago, IL',
    destCity:            'Memphis, TN',
    distanceMiles:       531,
    estimatedDriveHours: 8.5,
    pickupWindow:        '06:00–08:00',
    deliveryDeadline:    '06:00 +1',
  },
  // Player context
  hosHistory = [],
  currentDay = 1,
  level = 1,
  mode = 'pre_departure',    // 'pre_departure' | 'practice'
  // Callbacks
  addNotification = () => {},
  formatCurrency = (n) => '$' + n.toLocaleString(),
}) {
  // ── State ──────────────────────────────────────────────────────────────────
  const [hand, setHand]                         = useState([]);
  const [placedCards, setPlacedCards]           = useState([]);   // {instanceId, startMinute, ...card}
  const [selectedCard, setSelectedCard]         = useState(null); // instanceId
  const [screen, setScreen]                     = useState('puzzle'); // 'puzzle' | 'summary'
  const [validation, setValidation]             = useState({ isCompliant: false, violations: [] });
  const [timelineOffset, setTimelineOffset]     = useState(0);    // scroll offset px
  const [elapsedSeconds, setElapsedSeconds]     = useState(0);
  const [timerActive, setTimerActive]           = useState(false);
  const [summaryData, setSummaryData]           = useState(null);
  const [showRuleDetail, setShowRuleDetail]     = useState(null); // VT.* to show inline
  const [pendingDropMinute, setPendingDropMinute] = useState(null);
  const [errorShake, setErrorShake]             = useState(null);  // instanceId of shaking card
  const [windowWarning, setWindowWarning]       = useState(false); // <1h window remaining

  // ── Refs ───────────────────────────────────────────────────────────────────
  const timerRef        = useRef(null);
  const startTimeRef    = useRef(null);
  const tlRef           = useRef(null);   // timeline container ref
  const finishedRef     = useRef(false);

  // ── Derived state ──────────────────────────────────────────────────────────
  const shiftStart = useMemo(
    () => getShiftStartMinute(placedCards),
    [placedCards]
  );

  // All placed cards as HOS entries
  const entries = useMemo(
    () => placedCardsToEntries(placedCards),
    [placedCards]
  );

  // Remaining hours from engine
  const remaining = useMemo(() => {
    if (entries.length === 0) {
      return {
        driving:          R.MAX_DRIVING_MIN,
        window:           R.WINDOW_MIN,
        weeklyOnDuty:     R.WEEKLY_70_MIN,
        untilBreakNeeded: R.BREAK_TRIGGER_MIN,
      };
    }
    const currentMinute = entries.length > 0
      ? Math.max(...entries.map(e => e.startMinute + e.durationMinutes))
      : 0;
    return getRemainingHours(
      buildEngineEntries(hosHistory, entries),
      currentMinute,
      { weeklyPolicy: '70/8', sdpEnabled: level >= 20 }
    );
  }, [entries, hosHistory, level, shiftStart, placedCards]);

  // Card in hand that is currently selected
  const selectedCardObj = useMemo(
    () => hand.find(c => c.instanceId === selectedCard) || null,
    [hand, selectedCard]
  );

  // Which hand cards have been placed
  const placedIds = useMemo(
    () => new Set(placedCards.map(pc => pc.instanceId)),
    [placedCards]
  );

  const requiredIds = useMemo(
    () => hand.filter(c => c.required).map(c => c.instanceId),
    [hand]
  );
  const allRequiredPlaced = useMemo(
    () => requiredIds.every(id => placedIds.has(id)),
    [requiredIds, placedIds]
  );

  // ── Initialisation ─────────────────────────────────────────────────────────
  useEffect(() => {
    const generatedHand = buildHand(runData, level, mode);
    setHand(generatedHand);
    setTimerActive(true);
    startTimeRef.current = Date.now();
    setTimelineOffset(0);
    // Scroll timeline to 4am (a reasonable shift-start anchor)
    if (tlRef.current) {
      tlRef.current.scrollLeft = minToPx(4 * 60);
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Timer ──────────────────────────────────────────────────────────────────
  useEffect(() => {
    if (!timerActive) return;
    timerRef.current = setInterval(() => {
      setElapsedSeconds(Math.floor((Date.now() - (startTimeRef.current || Date.now())) / 1000));
    }, 1000);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [timerActive]);

  // ── Real-time validation ───────────────────────────────────────────────────
  useEffect(() => {
    if (entries.length === 0) {
      setValidation({ isCompliant: false, violations: [] });
      return;
    }
    const allEntries = buildEngineEntries(hosHistory, entries);
    const result = validateSchedule(allEntries, {
      weeklyPolicy:  '70/8',
      sdpEnabled:    level >= 20,
      currentMinute: entries[entries.length - 1]?.startMinute + entries[entries.length - 1]?.durationMinutes,
    });
    setValidation(result);
  }, [entries, hosHistory, level]);

  // ── 14h window countdown warning ──────────────────────────────────────────
  useEffect(() => {
    setWindowWarning(remaining.window > 0 && remaining.window < 60); // < 1h left
  }, [remaining.window]);

  // ── Handlers ───────────────────────────────────────────────────────────────

  /** Select a card from the hand */
  const handleSelectCard = useCallback((instanceId) => {
    setSelectedCard(prev => prev === instanceId ? null : instanceId);
    setShowRuleDetail(null);
  }, []);

  /** Remove a placed card and return it to hand */
  const handleRemovePlaced = useCallback((instanceId) => {
    setPlacedCards(prev => prev.filter(pc => pc.instanceId !== instanceId));
    setSelectedCard(null);
  }, []);

  /**
   * Place the selected card at a given timeline minute (snapped to 30-min grid).
   * Checks for overlap; if overlap, triggers shake animation and rejects.
   */
  const handleTimelineTap = useCallback((tapMinute) => {
    if (!selectedCardObj) return;
    const snapped = snapToGrid(tapMinute);
    const newEnd  = snapped + selectedCardObj.durationMinutes;

    // Check overlap with existing placed cards
    const overlaps = placedCards.some(pc => {
      const pcEnd = pc.startMinute + pc.durationMinutes;
      return !(newEnd <= pc.startMinute || snapped >= pcEnd);
    });

    if (overlaps) {
      setErrorShake(selectedCardObj.instanceId);
      setTimeout(() => setErrorShake(null), 500);
      return;
    }

    // Out of day bounds check
    if (snapped < 0 || newEnd > FULL_DAY_MIN) return;

    const newPlaced = {
      ...selectedCardObj,
      startMinute: snapped,
    };

    setPlacedCards(prev => [...prev, newPlaced]);
    setSelectedCard(null);
    setPendingDropMinute(null);
  }, [selectedCardObj, placedCards]);

  /** Hover over timeline — show ghost position */
  const handleTimelineHover = useCallback((minute) => {
    if (!selectedCardObj) return;
    setPendingDropMinute(snapToGrid(minute));
  }, [selectedCardObj]);

  const handleTimelineLeave = useCallback(() => {
    setPendingDropMinute(null);
  }, []);

  /** File the logbook — requires all required cards placed and no violations */
  const handleFileLogbook = useCallback(() => {
    if (finishedRef.current) return;
    if (!allRequiredPlaced || !validation.isCompliant) return;

    finishedRef.current = true;
    setTimerActive(false);
    if (timerRef.current) clearInterval(timerRef.current);

    const timeToFile = elapsedSeconds;

    // Build hosCompliance object for App.jsx
    const finalEntries   = placedCardsToEntries(placedCards);
    const endOfShift     = finalEntries.length > 0
      ? Math.max(...finalEntries.map(e => e.startMinute + e.durationMinutes))
      : 0;
    const rem            = getRemainingHours(
      buildEngineEntries(hosHistory, finalEntries),
      endOfShift,
      { weeklyPolicy: '70/8' }
    );

    const hosCompliance = {
      isCompliant:    true,
      violations:     [],
      hoursRemaining: { driving: rem.driving, onDuty: rem.window },
      weeklyHoursUsed: R.WEEKLY_70_MIN - rem.weeklyOnDuty,
    };

    // Practice mode best
    let newBest = false;
    if (mode === 'practice') {
      newBest = savePracticeBest(timeToFile);
    }

    setSummaryData({
      outcome:      'filed_compliant',
      hosCompliance,
      timeToFile,
      newBest,
      violations:   [],
      weeklyUsed:   hosCompliance.weeklyHoursUsed,
    });
    setScreen('summary');
  }, [
    allRequiredPlaced, validation.isCompliant, elapsedSeconds,
    placedCards, hosHistory, mode,
  ]);

  /** Skip filing — marks hosCompliance with violations */
  const handleSkip = useCallback(() => {
    if (finishedRef.current) return;
    finishedRef.current = true;
    setTimerActive(false);
    if (timerRef.current) clearInterval(timerRef.current);

    const hosCompliance = {
      isCompliant:    false,
      violations:     [{ rule: VT.ELD_MISSING, severity: 'major',
                         description: 'Logbook not filed before departure.' }],
      hoursRemaining: { driving: R.MAX_DRIVING_MIN, onDuty: R.WINDOW_MIN },
      weeklyHoursUsed: 0,
    };

    onComplete({ outcome: 'skipped', hosCompliance, timeToFile: elapsedSeconds });
  }, [onComplete, elapsedSeconds]);

  /** File with violations (only available if all required placed but violations exist) */
  const handleFileWithViolations = useCallback(() => {
    if (finishedRef.current) return;
    finishedRef.current = true;
    setTimerActive(false);
    if (timerRef.current) clearInterval(timerRef.current);

    const violations = validation.violations.map(v => ({
      rule:        v.rule,
      severity:    v.severity,
      description: v.description,
    }));

    const hosCompliance = {
      isCompliant:    false,
      violations,
      hoursRemaining: { driving: remaining.driving, onDuty: remaining.window },
      weeklyHoursUsed: R.WEEKLY_70_MIN - remaining.weeklyOnDuty,
    };

    setSummaryData({
      outcome:      'filed_violations',
      hosCompliance,
      timeToFile:   elapsedSeconds,
      newBest:      false,
      violations,
      weeklyUsed:   hosCompliance.weeklyHoursUsed,
    });
    setScreen('summary');
  }, [validation.violations, remaining, elapsedSeconds]);

  /** Complete from summary screen → calls parent onComplete */
  const handleComplete = useCallback(() => {
    if (!summaryData) return;
    onComplete({
      outcome:      summaryData.outcome,
      hosCompliance: summaryData.hosCompliance,
      timeToFile:   summaryData.timeToFile,
    });
  }, [summaryData, onComplete]);

  // ── Timeline touch / tap support ───────────────────────────────────────────
  const handleTimelineTouchEnd = useCallback((e) => {
    if (!selectedCardObj || !tlRef.current) return;
    const touch = e.changedTouches[0];
    const rect  = tlRef.current.getBoundingClientRect();
    const x     = touch.clientX - rect.left + tlRef.current.scrollLeft;
    handleTimelineTap(pxToMin(x));
  }, [selectedCardObj, handleTimelineTap]);

  const handleTimelineClick = useCallback((e) => {
    if (!selectedCardObj || !tlRef.current) return;
    const rect = tlRef.current.getBoundingClientRect();
    const x    = e.clientX - rect.left + tlRef.current.scrollLeft;
    handleTimelineTap(pxToMin(x));
  }, [selectedCardObj, handleTimelineTap]);

  // Mouse/touch move for ghost preview
  const handleTimelineMouseMove = useCallback((e) => {
    if (!selectedCardObj || !tlRef.current) return;
    const rect = tlRef.current.getBoundingClientRect();
    const x    = e.clientX - rect.left + tlRef.current.scrollLeft;
    handleTimelineHover(pxToMin(x));
  }, [selectedCardObj, handleTimelineHover]);

  const handleTimelineTouchMove = useCallback((e) => {
    if (!selectedCardObj || !tlRef.current) return;
    const touch = e.touches[0];
    const rect  = tlRef.current.getBoundingClientRect();
    const x     = touch.clientX - rect.left + tlRef.current.scrollLeft;
    handleTimelineHover(pxToMin(x));
  }, [selectedCardObj, handleTimelineHover]);

  // ── Render helpers ─────────────────────────────────────────────────────────

  /** Format elapsed seconds as mm:ss */
  function fmtTimer(secs) {
    const m = Math.floor(secs / 60);
    const s = secs % 60;
    return `${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
  }

  // ── RENDER: PUZZLE SCREEN ──────────────────────────────────────────────────
  if (screen === 'puzzle') return renderPuzzle();
  if (screen === 'summary') return renderSummary();
  return null;

  // ─────────────────────────────────────────────────────────────────────────
  // RENDER FUNCTIONS
  // ─────────────────────────────────────────────────────────────────────────

  function renderPuzzle() {
    const drivingUsed       = R.MAX_DRIVING_MIN - remaining.driving;
    const windowUsed        = shiftStart != null ? R.WINDOW_MIN - remaining.window : 0;
    const breakDrivingUsed  = R.BREAK_TRIGGER_MIN - remaining.untilBreakNeeded;
    const drivingPct        = Math.min(100, Math.round((drivingUsed / R.MAX_DRIVING_MIN) * 100));
    const windowPct         = Math.min(100, Math.round((windowUsed  / R.WINDOW_MIN) * 100));
    const breakPct          = Math.min(100, Math.round((breakDrivingUsed / R.BREAK_TRIGGER_MIN) * 100));
    const windowDanger      = windowPct >= 85;
    const drivingDanger     = drivingPct >= 90;
    const breakDanger       = breakPct  >= 85;

    // Which violations affect driving specifically (for card glow)
    const windowViolation   = validation.violations.some(v => v.rule === VT.WINDOW_LIMIT);
    const drivingViolation  = validation.violations.some(v => v.rule === VT.DRIVING_LIMIT);
    const breakViolation    = validation.violations.some(v => v.rule === VT.BREAK_REQUIRED);

    const canFile = allRequiredPlaced && validation.isCompliant;
    const canForceFile = allRequiredPlaced && !validation.isCompliant && validation.violations.length > 0;

    return (
      <div style={{
        display: 'flex', flexDirection: 'column',
        height: '100%', maxWidth: 480, width: '100%',
        background: '#0d1117', color: '#e6edf3',
        fontFamily: FONT, overflow: 'hidden', position: 'relative',
        WebkitTapHighlightColor: 'transparent',
      }}>
        <style>{HP_CSS}</style>

        {/* ── HEADER ── */}
        <div style={{
          display: 'flex', alignItems: 'center', gap: 8,
          padding: '10px 14px', background: '#161b22',
          borderBottom: '1px solid #30363d', flexShrink: 0,
        }}>
          <div style={{
            fontSize: 10, fontWeight: 700, letterSpacing: '.07em',
            padding: '3px 8px', borderRadius: 4,
            background: mode === 'practice' ? '#1a3628' : '#1a2744',
            color: mode === 'practice' ? '#3fb950' : '#58a6ff',
            border: `1px solid ${mode === 'practice' ? '#1a4a30' : '#1f3a5a'}`,
          }}>
            {mode === 'practice' ? 'PRACTICE' : 'PRE-DEPARTURE'}
          </div>
          <div style={{ flex: 1, fontSize: 13, fontWeight: 600 }}>HOS Logbook</div>
          <div style={{ fontFamily: MONO, fontSize: 12, color: '#8b949e' }}>{fmtTimer(elapsedSeconds)}</div>
          <button
            onClick={onClose}
            style={{
              width: 32, height: 32, border: '1px solid #30363d',
              background: 'none', color: '#8b949e', borderRadius: 6,
              cursor: 'pointer', fontSize: 14, display: 'flex',
              alignItems: 'center', justifyContent: 'center',
              WebkitTapHighlightColor: 'transparent', minWidth: 44, minHeight: 44,
            }}
            aria-label="Exit puzzle"
          >✕</button>
        </div>

        {/* ── MARCUS BRIEF ── */}
        <div style={{
          display: 'flex', gap: 10, padding: '10px 14px',
          background: '#161b22', borderBottom: '1px solid #30363d', flexShrink: 0,
        }}>
          <img src={_MARCUS_PORTRAIT_URI} alt="Marcus Rodriguez" style={{
            width: 34, height: 34, borderRadius: '50%',
            objectFit: 'cover', objectPosition: 'center 22%',
            border: '1px solid #1f3a5a',
            flexShrink: 0, display: 'block',
          }} />
          <div style={{ fontSize: 11.5, color: '#8b949e', lineHeight: 1.5 }}>
            <strong style={{ color: '#e6edf3' }}>"File your log before you roll."</strong>
            {' '}{runData.originCity} → {runData.destCity}, {runData.distanceMiles} mi.
            {' '}Arrange all cards into a compliant schedule, then FILE.
            <div style={{ marginTop: 4, fontSize: 10.5, color: '#6e7681' }}>
              ELD required — routes exceed 150 air miles in interstate commerce.
              Short-haul exemption does not apply. 49 CFR 395.1(e).
            </div>
          </div>
        </div>

        {/* ── RUN DATA STRIP ── */}
        <div style={{
          display: 'flex', borderBottom: '1px solid #30363d',
          background: '#161b22', flexShrink: 0,
        }}>
          {[
            { label: 'Distance', val: `${runData.distanceMiles} mi` },
            { label: 'Drive time', val: `~${runData.estimatedDriveHours}h`, warn: runData.estimatedDriveHours >= 8 },
            { label: 'Pickup', val: runData.pickupWindow },
            { label: 'Delivery', val: runData.deliveryDeadline },
          ].map(({ label, val, warn }) => (
            <div key={label} style={{
              flex: 1, padding: '7px 10px',
              borderRight: '1px solid #30363d',
            }}>
              <div style={{ fontSize: 9, color: '#6e7681', textTransform: 'uppercase', letterSpacing: '.05em', marginBottom: 2 }}>{label}</div>
              <div style={{ fontSize: 12, fontWeight: 500, color: warn ? '#d29922' : '#e6edf3' }}>{val}</div>
            </div>
          ))}
        </div>

        {/* ── COUNTERS ── */}
        <div style={{
          display: 'flex', background: '#161b22',
          borderBottom: '1px solid #30363d', flexShrink: 0,
        }}>
          {/* 11h driving */}
          <div style={{ flex: 1, padding: '7px 10px', borderRight: '1px solid #30363d' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9.5, color: '#6e7681', marginBottom: 3 }}>
              <span>11h driving</span>
              <span style={{ fontFamily: MONO, fontWeight: 700, color: drivingDanger ? '#f85149' : '#58a6ff' }}>
                {fmtMin(remaining.driving)} left
              </span>
            </div>
            <div style={{ height: 3, background: '#21262d', borderRadius: 2, overflow: 'hidden' }}>
              <div style={{ height: '100%', borderRadius: 2, width: `${drivingPct}%`, transition: 'width .3s',
                background: drivingViolation ? '#f85149' : drivingDanger ? '#f0a845' : '#58a6ff' }} />
            </div>
          </div>
          {/* 14h window */}
          <div style={{ flex: 1, padding: '7px 10px', borderRight: '1px solid #30363d' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9.5, color: '#6e7681', marginBottom: 3 }}>
              <span>14h window</span>
              <span style={{
                fontFamily: MONO, fontWeight: 700,
                color: windowViolation ? '#f85149' : windowDanger ? '#f85149' : '#f0a845',
                animation: windowWarning ? 'hp-pulse 1.2s infinite' : undefined,
              }}>
                {shiftStart != null ? fmtMin(remaining.window) + ' left' : '--'}
              </span>
            </div>
            <div style={{ height: 3, background: '#21262d', borderRadius: 2, overflow: 'hidden' }}>
              <div style={{ height: '100%', borderRadius: 2, width: `${windowPct}%`, transition: 'width .3s',
                background: windowViolation ? '#f85149' : windowDanger ? '#f85149' : '#f0a845' }} />
            </div>
          </div>
          {/* 8h break */}
          <div style={{ flex: 1, padding: '7px 10px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9.5, color: '#6e7681', marginBottom: 3 }}>
              <span>break in</span>
              <span style={{ fontFamily: MONO, fontWeight: 700, color: breakDanger ? '#f85149' : '#3fb950' }}>
                {remaining.untilBreakNeeded <= 0 ? 'NOW' : fmtMin(remaining.untilBreakNeeded)}
              </span>
            </div>
            <div style={{ height: 3, background: '#21262d', borderRadius: 2, overflow: 'hidden' }}>
              <div style={{ height: '100%', borderRadius: 2, width: `${breakPct}%`, transition: 'width .3s',
                background: breakViolation ? '#f85149' : breakDanger ? '#f85149' : '#3fb950' }} />
            </div>
          </div>
        </div>

        {/* ── TIMELINE ── */}
        <div style={{ flex: 1, overflow: 'hidden', position: 'relative', minHeight: 120 }}>
          {/* Timeline scroll container */}
          <div
            ref={tlRef}
            onClick={handleTimelineClick}
            onMouseMove={handleTimelineMouseMove}
            onMouseLeave={handleTimelineLeave}
            onTouchEnd={handleTimelineTouchEnd}
            onTouchMove={handleTimelineTouchMove}
            style={{
              overflowX: 'auto', overflowY: 'hidden',
              height: '100%', cursor: selectedCardObj ? 'crosshair' : 'grab',
              WebkitOverflowScrolling: 'touch',
              scrollbarWidth: 'thin', scrollbarColor: '#30363d #161b22',
            }}
          >
            <div style={{ width: TIMELINE_WIDTH, height: '100%', position: 'relative', paddingTop: 24 }}>

              {/* Time labels row */}
              <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 24, display: 'flex' }}>
                {Array.from({ length: 24 }, (_, h) => (
                  <div key={h} style={{
                    position: 'absolute', left: minToPx(h * 60),
                    width: minToPx(60), height: 24,
                    borderRight: '1px solid #30363d',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 9, fontFamily: MONO, color: h % 2 === 0 ? '#8b949e' : '#6e7681',
                  }}>
                    {fmtClock(h * 60)}
                  </div>
                ))}
              </div>

              {/* Track area */}
              <div style={{ position: 'absolute', top: 24, left: 0, right: 0, bottom: 0, background: '#161b22' }}>

                {/* Grid lines */}
                {Array.from({ length: 48 }, (_, i) => (
                  <div key={i} style={{
                    position: 'absolute', top: 0, bottom: 0,
                    left: minToPx(i * 30), width: 1,
                    background: i % 2 === 0 ? '#30363d' : '#21262d',
                  }} />
                ))}

                {/* 14h WINDOW BRACKET — always visible once shift starts */}
                {shiftStart != null && (
                  <div style={{
                    position: 'absolute', top: 0, bottom: 0,
                    left: minToPx(shiftStart),
                    width: minToPx(R.WINDOW_MIN),
                    pointerEvents: 'none',
                    zIndex: 1,
                  }}>
                    {/* Fill */}
                    <div style={{
                      position: 'absolute', inset: 0,
                      background: 'rgba(240,168,69,.04)',
                      borderLeft: `2px solid ${windowViolation ? '#f85149' : '#f0a845'}`,
                      borderRight: `2px solid ${windowViolation ? '#f85149' : '#f0a845'}`,
                      animation: windowWarning ? 'hp-bracket 1.2s ease infinite' : undefined,
                    }} />
                    {/* Label at right edge */}
                    <div style={{
                      position: 'absolute', top: 4, right: 3,
                      fontSize: 9, fontWeight: 700, fontFamily: MONO,
                      color: windowViolation ? '#f85149' : windowDanger ? '#f85149' : '#f0a845',
                      background: 'rgba(13,17,23,.85)',
                      padding: '2px 4px', borderRadius: 3,
                      animation: windowWarning ? 'hp-countdn 1.2s infinite' : undefined,
                    }}>
                      {windowViolation ? 'EXPIRED' : `${fmtClock(shiftStart + R.WINDOW_MIN)} closes`}
                    </div>
                    {/* Bottom tick */}
                    <div style={{
                      position: 'absolute', bottom: 0, left: 0, right: 0,
                      height: 2, background: '#f0a845', opacity: .5,
                    }} />
                  </div>
                )}

                {/* GHOST CARD — preview of where selected card will land */}
                {selectedCardObj && pendingDropMinute != null && (() => {
                  const col = selectedCardObj.isSDP
                    ? CARD_COLORS.sdp
                    : CARD_COLORS[selectedCardObj.type];
                  const ghostEnd = pendingDropMinute + selectedCardObj.durationMinutes;
                  const willOverlap = placedCards.some(pc => {
                    const pcEnd = pc.startMinute + pc.durationMinutes;
                    return !(ghostEnd <= pc.startMinute || pendingDropMinute >= pcEnd);
                  });
                  return (
                    <div style={{
                      position: 'absolute',
                      top: 8, bottom: 8,
                      left: minToPx(pendingDropMinute),
                      width: minToPx(selectedCardObj.durationMinutes),
                      background: willOverlap ? 'rgba(248,81,73,.15)' : `${col.bg}cc`,
                      border: `1px dashed ${willOverlap ? '#f85149' : col.border}`,
                      borderRadius: 6, zIndex: 5, pointerEvents: 'none',
                      display: 'flex', alignItems: 'center', padding: '0 6px',
                    }}>
                      <span style={{ fontSize: 9, color: willOverlap ? '#f85149' : col.label }}>
                        {willOverlap ? 'overlap' : selectedCardObj.shortLabel}
                      </span>
                    </div>
                  );
                })()}

                {/* PLACED CARDS */}
                {placedCards.map(pc => {
                  const col      = pc.isSDP ? CARD_COLORS.sdp : CARD_COLORS[pc.type];
                  const hasViol  = validation.violations.some(
                    v => v.atMinute >= pc.startMinute && v.atMinute < pc.startMinute + pc.durationMinutes
                  );
                  const isNarrow = pc.durationMinutes < 60;

                  return (
                    <div
                      key={pc.instanceId}
                      onClick={(e) => { e.stopPropagation(); handleRemovePlaced(pc.instanceId); }}
                      style={{
                        position: 'absolute',
                        top: 8, bottom: 8,
                        left: minToPx(pc.startMinute),
                        width: minToPx(pc.durationMinutes) - 1,
                        background: hasViol ? 'rgba(60,31,32,.9)' : col.bg,
                        border: `1px solid ${hasViol ? '#f85149' : col.border}`,
                        borderRadius: 6, cursor: 'pointer',
                        display: 'flex', alignItems: 'center', padding: '0 6px',
                        overflow: 'hidden', zIndex: 2,
                        animation: hasViol ? 'hp-glow 2s infinite' : undefined,
                        minWidth: 12,
                      }}
                      title="Tap to remove"
                    >
                      {isNarrow ? (
                        <div style={{
                          writingMode: 'vertical-lr', transform: 'rotate(180deg)',
                          fontSize: 8, color: hasViol ? '#f85149' : col.label, lineHeight: 1,
                        }}>{col.code}</div>
                      ) : (
                        <div style={{ overflow: 'hidden' }}>
                          <div style={{ fontSize: 8, fontWeight: 700, color: hasViol ? '#f8a8a8' : col.label, letterSpacing: '.06em', marginBottom: 1 }}>
                            {col.code}
                          </div>
                          <div style={{ fontSize: 10, fontWeight: 500, color: hasViol ? '#f8c8c8' : '#e6edf3', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                            {pc.shortLabel || pc.label}
                          </div>
                          <div style={{ fontSize: 9, color: hasViol ? '#f8a8a8' : '#8b949e', fontFamily: MONO }}>
                            {fmtMin(pc.durationMinutes)}
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}

              </div>{/* end track */}
            </div>{/* end timeline-inner */}
          </div>{/* end scroll */}

          {/* Selected-card overlay hint */}
          {selectedCardObj && (
            <div style={{
              position: 'absolute', top: 8, left: 0, right: 0,
              display: 'flex', justifyContent: 'center', pointerEvents: 'none', zIndex: 10,
            }}>
              <div style={{
                background: 'rgba(13,17,23,.88)', border: '1px solid #30363d',
                borderRadius: 20, padding: '4px 12px', fontSize: 11,
                color: '#8b949e', animation: 'hp-fadein .2s ease',
              }}>
                Tap timeline to place <strong style={{ color: '#e6edf3' }}>{selectedCardObj.shortLabel}</strong>
              </div>
            </div>
          )}
        </div>{/* end timeline-wrap */}

        {/* ── VIOLATION BANNER ── */}
        {validation.violations.length > 0 && (
          <div style={{
            background: '#3c1f20', borderTop: '1px solid #5a1f20',
            padding: '8px 12px', display: 'flex', alignItems: 'center', gap: 8,
            flexShrink: 0, animation: 'hp-slidein .25s ease',
          }}>
            <div style={{
              width: 20, height: 20, borderRadius: '50%', background: '#f85149',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 11, fontWeight: 700, color: '#fff', flexShrink: 0,
            }}>!</div>
            <div style={{ flex: 1, fontSize: 11, color: '#f8a8a8', lineHeight: 1.4 }}>
              <strong style={{ color: '#f8c8c8' }}>
                {getViolationDetails(validation.violations[0].rule).title}
              </strong>
              {' — '}{validation.violations[0].description.slice(0, 90)}{validation.violations[0].description.length > 90 ? '…' : ''}
            </div>
            <button
              onClick={() => setShowRuleDetail(
                showRuleDetail === validation.violations[0].rule ? null : validation.violations[0].rule
              )}
              style={{
                fontSize: 10, color: '#f85149', background: 'none',
                border: '1px solid #5a1f20', padding: '3px 8px', borderRadius: 4,
                cursor: 'pointer', flexShrink: 0, minHeight: 28,
                WebkitTapHighlightColor: 'transparent', fontFamily: FONT,
              }}
            >why?</button>
          </div>
        )}

        {/* ── RULE DETAIL EXPANDER ── */}
        {showRuleDetail && (() => {
          const detail = getViolationDetails(showRuleDetail);
          return (
            <div style={{
              background: '#1a0a0a', borderTop: '1px solid #5a1f20',
              padding: '10px 14px', flexShrink: 0,
              animation: 'hp-fadein .2s ease',
            }}>
              <div style={{ fontSize: 10, fontWeight: 700, color: '#f85149', letterSpacing: '.06em', marginBottom: 4 }}>
                {detail.code} — {detail.regulation}
              </div>
              <div style={{ fontSize: 11, color: '#f8c8c8', lineHeight: 1.5, marginBottom: 6 }}>
                {detail.description}
              </div>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                <span style={{ fontSize: 10, background: '#3c1f20', color: '#f8a8a8', padding: '2px 6px', borderRadius: 4 }}>
                  {detail.fineRange}
                </span>
                <span style={{ fontSize: 10, background: '#2a200a', color: '#d29922', padding: '2px 6px', borderRadius: 4 }}>
                  CSA: {detail.csaPoints}
                </span>
              </div>
            </div>
          );
        })()}

        {/* ── HAND ── */}
        <div style={{
          background: '#161b22', borderTop: '1px solid #30363d',
          padding: '10px 12px', flexShrink: 0,
        }}>
          <div style={{
            display: 'flex', justifyContent: 'space-between',
            fontSize: 9.5, color: '#6e7681', letterSpacing: '.05em', marginBottom: 8,
          }}>
            <span>HAND</span>
            <span style={{ color: '#8b949e' }}>
              {hand.filter(c => !placedIds.has(c.instanceId)).length} unplaced
              {' · '}{hand.filter(c => c.required && !placedIds.has(c.instanceId)).length} required
            </span>
          </div>

          <div style={{
            display: 'flex', gap: 6, overflowX: 'auto', paddingBottom: 4,
            scrollbarWidth: 'thin', scrollbarColor: '#30363d #161b22',
          }}>
            {hand.map(card => {
              const isPlaced   = placedIds.has(card.instanceId);
              const isSelected = selectedCard === card.instanceId;
              const col        = card.isSDP ? CARD_COLORS.sdp : CARD_COLORS[card.type];
              const isShaking  = errorShake === card.instanceId;

              return (
                <div
                  key={card.instanceId}
                  onClick={() => !isPlaced && handleSelectCard(card.instanceId)}
                  style={{
                    flexShrink: 0, width: 84, minHeight: 44,
                    background: isPlaced
                      ? 'rgba(22,27,34,.5)'
                      : isSelected
                        ? '#1a2030'
                        : '#21262d',
                    border: `1px solid ${isPlaced ? '#21262d' : isSelected ? '#58a6ff' : '#30363d'}`,
                    borderRadius: 8, padding: 8, cursor: isPlaced ? 'default' : 'pointer',
                    transition: 'transform .15s, border-color .15s',
                    transform: isSelected ? 'translateY(-3px)' : 'none',
                    position: 'relative', opacity: isPlaced ? .45 : 1,
                    animation: isShaking ? 'hp-shake .4s ease' : undefined,
                    WebkitTapHighlightColor: 'transparent',
                  }}
                  aria-label={`${card.label} — ${fmtMin(card.durationMinutes)}${isPlaced ? ' (placed)' : isSelected ? ' (selected)' : ''}`}
                >
                  {/* Color stripe */}
                  <div style={{ height: 3, borderRadius: 2, marginBottom: 5, background: col.stripe }} />
                  <div style={{ fontSize: 10, fontWeight: 500, color: '#e6edf3', lineHeight: 1.3, marginBottom: 3 }}>
                    {card.shortLabel}
                  </div>
                  <div style={{ fontSize: 11, fontWeight: 700, fontFamily: MONO, color: '#8b949e' }}>
                    {fmtMin(card.durationMinutes)}
                  </div>
                  <div style={{ fontSize: 8, color: '#6e7681', marginTop: 2, letterSpacing: '.03em' }}>
                    {card.isSDP ? 'SDP ✦' : col.code}
                    {card.required && !isPlaced && (
                      <span style={{ color: '#d29922', marginLeft: 3 }}>★</span>
                    )}
                  </div>
                  {/* Placed indicator dot */}
                  {isPlaced && (
                    <div style={{
                      position: 'absolute', top: 4, right: 4,
                      width: 6, height: 6, borderRadius: '50%', background: '#3fb950',
                    }} />
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* ── FILE BUTTON ── */}
        <div style={{ padding: '8px 14px', background: '#161b22', borderTop: '1px solid #30363d', flexShrink: 0 }}>
          {canFile ? (
            <button
              onClick={handleFileLogbook}
              style={{
                width: '100%', padding: 12, borderRadius: 8, border: 'none',
                background: '#238636', color: '#fff',
                fontFamily: FONT, fontSize: 14, fontWeight: 700,
                letterSpacing: '.04em', cursor: 'pointer',
                animation: 'hp-pop .4s ease',
                WebkitTapHighlightColor: 'transparent', minHeight: 44,
              }}
            >
              ✓ FILE LOGBOOK — COMPLIANT
            </button>
          ) : (
            <div style={{ display: 'flex', gap: 8 }}>
              <button
                onClick={handleSkip}
                style={{
                  flex: 1, padding: 12, borderRadius: 8,
                  border: '1px solid #30363d', background: 'none',
                  color: '#6e7681', fontFamily: FONT, fontSize: 12, fontWeight: 500,
                  cursor: 'pointer', WebkitTapHighlightColor: 'transparent', minHeight: 44,
                }}
              >
                Skip
              </button>
              <button
                onClick={canForceFile ? handleFileWithViolations : undefined}
                disabled={!canForceFile}
                style={{
                  flex: 3, padding: 12, borderRadius: 8, border: 'none',
                  background: canForceFile ? '#3c2020' : '#21262d',
                  color: canForceFile ? '#f85149' : '#6e7681',
                  fontFamily: FONT, fontSize: 13, fontWeight: 600,
                  cursor: canForceFile ? 'pointer' : 'not-allowed',
                  WebkitTapHighlightColor: 'transparent', minHeight: 44,
                }}
              >
                {!allRequiredPlaced
                  ? `Place ${requiredIds.filter(id => !placedIds.has(id)).length} required cards (★)`
                  : validation.violations.length > 0
                    ? 'File with violations'
                    : 'Building schedule…'
                }
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  // ─────────────────────────────────────────────────────────────────────────
  function renderSummary() {
    if (!summaryData) return null;
    const { outcome, timeToFile, newBest, violations, weeklyUsed } = summaryData;
    const compliant = outcome === 'filed_compliant';
    const practiceBest = mode === 'practice' ? getPracticeBest() : 0;

    return (
      <div style={{
        display: 'flex', flexDirection: 'column',
        height: '100%', maxWidth: 480, width: '100%',
        background: '#0d1117', color: '#e6edf3',
        fontFamily: FONT, overflow: 'hidden',
        WebkitTapHighlightColor: 'transparent',
      }}>
        <style>{HP_CSS}</style>

        {/* Header */}
        <div style={{
          display: 'flex', alignItems: 'center', gap: 8,
          padding: '10px 14px', background: '#161b22',
          borderBottom: '1px solid #30363d', flexShrink: 0,
        }}>
          <div style={{
            fontSize: 10, fontWeight: 700, letterSpacing: '.07em',
            padding: '3px 8px', borderRadius: 4,
            background: compliant ? '#1a3628' : '#3c1f20',
            color: compliant ? '#3fb950' : '#f85149',
            border: `1px solid ${compliant ? '#1a4a30' : '#5a1f20'}`,
          }}>
            {compliant ? 'FILED' : outcome === 'skipped' ? 'SKIPPED' : 'FILED — VIOLATIONS'}
          </div>
          <div style={{ flex: 1, fontSize: 13, fontWeight: 600 }}>
            HOS Logbook {compliant ? '— compliant' : '— non-compliant'}
          </div>
        </div>

        <div style={{ flex: 1, overflowY: 'auto', padding: '20px 16px', display: 'flex', flexDirection: 'column', gap: 16 }}>

          {/* Result icon */}
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 12, paddingTop: 8 }}>
            <div style={{
              width: 60, height: 60, borderRadius: '50%',
              background: compliant ? '#1a3628' : '#3c1f20',
              border: `2px solid ${compliant ? '#3fb950' : '#f85149'}`,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 26, animation: 'hp-win .5s ease',
            }}>
              {compliant ? '✓' : '✗'}
            </div>
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 20, fontWeight: 700, color: compliant ? '#3fb950' : '#f85149' }}>
                {compliant ? 'Logbook filed' : outcome === 'skipped' ? 'Skipped' : 'Filed with violations'}
              </div>
              <div style={{ fontSize: 12, color: '#8b949e', marginTop: 4, lineHeight: 1.5 }}>
                {compliant
                  ? "Schedule is HOS-compliant. ELD synced. You're clear to roll."
                  : outcome === 'skipped'
                    ? "No logbook filed. hosCompliance flagged — DOT officer will find it."
                    : "Violations in hosCompliance. DOT Documents hex will flag these."}
              </div>
            </div>
          </div>

          {/* Stats grid */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
            {[
              {
                label: 'TIME TO FILE',
                val: fmtTimer(timeToFile),
                sub: mode === 'practice' && practiceBest > 0
                  ? `Best: ${fmtTimer(practiceBest)}${newBest ? ' ← NEW' : ''}`
                  : null,
                color: '#58a6ff',
              },
              {
                label: 'VIOLATIONS',
                val: String(violations.length),
                sub: violations.length === 0 ? 'Clean logbook' : null,
                color: violations.length === 0 ? '#3fb950' : '#f85149',
              },
              {
                label: 'WEEKLY USED',
                val: fmtMin(weeklyUsed),
                sub: `${fmtMin(R.WEEKLY_70_MIN - weeklyUsed)} remaining`,
                color: weeklyUsed > R.WEEKLY_60_MIN ? '#d29922' : '#58a6ff',
              },
              {
                label: '30-MIN BREAK',
                val: violations.some(v => v.rule === VT.BREAK_REQUIRED) ? 'MISSED' : 'MET',
                sub: violations.some(v => v.rule === VT.BREAK_REQUIRED) ? '49 CFR 395.3(a)(3)' : null,
                color: violations.some(v => v.rule === VT.BREAK_REQUIRED) ? '#f85149' : '#3fb950',
              },
            ].map(({ label, val, sub, color }) => (
              <div key={label} style={{
                background: '#161b22', border: '1px solid #30363d',
                borderRadius: 8, padding: 12,
              }}>
                <div style={{ fontSize: 9, color: '#6e7681', letterSpacing: '.05em', marginBottom: 4 }}>{label}</div>
                <div style={{ fontSize: 20, fontWeight: 700, fontFamily: MONO, color }}>{val}</div>
                {sub && <div style={{ fontSize: 10, color: '#8b949e', marginTop: 2 }}>{sub}</div>}
              </div>
            ))}
          </div>

          {/* Violations list */}
          {violations.length > 0 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {violations.map((v, i) => {
                const detail = getViolationDetails(v.rule);
                return (
                  <div key={i} style={{
                    background: '#3c1f20', border: '1px solid #5a1f20',
                    borderRadius: 8, padding: 12,
                  }}>
                    <div style={{ fontSize: 10, color: '#f85149', fontWeight: 700, marginBottom: 4 }}>
                      {detail.code} — {detail.title}
                    </div>
                    <div style={{ fontSize: 11, color: '#f8c8c8', lineHeight: 1.4, marginBottom: 6 }}>
                      {detail.description.slice(0, 120)}{detail.description.length > 120 ? '…' : ''}
                    </div>
                    <div style={{ display: 'flex', gap: 6 }}>
                      <span style={{ fontSize: 10, background: '#5a1f20', color: '#f8a8a8', padding: '2px 6px', borderRadius: 4 }}>
                        {detail.fineRange}
                      </span>
                      <span style={{ fontSize: 10, background: '#2a200a', color: '#d29922', padding: '2px 6px', borderRadius: 4 }}>
                        {detail.csaPoints}
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* Marcus quote */}
          <div style={{
            background: '#161b22', border: '1px solid #30363d',
            borderRadius: 8, padding: '12px 14px',
            display: 'flex', gap: 10, alignItems: 'flex-start',
          }}>
            <img src={_MARCUS_PORTRAIT_URI} alt="Marcus Rodriguez" style={{
              width: 30, height: 30, borderRadius: '50%',
              objectFit: 'cover', objectPosition: 'center 22%',
              border: '1px solid #1f3a5a',
              flexShrink: 0, display: 'block',
            }} />
            <div style={{ fontSize: 12, color: '#8b949e', lineHeight: 1.5, fontStyle: 'italic' }}>
              {compliant
                ? '"Your recordkeeping is what got you through this. That\'s not luck."'
                : outcome === 'skipped'
                  ? '"Your log didn\'t match the road. That\'s not a paperwork problem — that\'s a federal problem."'
                  : '"Build your day before the day builds you."'
              }
            </div>
          </div>
        </div>

        {/* Complete button */}
        <div style={{ padding: '12px 16px', background: '#161b22', borderTop: '1px solid #30363d', flexShrink: 0 }}>
          <button
            onClick={handleComplete}
            style={{
              width: '100%', padding: 13, borderRadius: 8, border: 'none',
              background: compliant ? '#238636' : '#21262d',
              color: compliant ? '#fff' : '#8b949e',
              fontFamily: FONT, fontSize: 14, fontWeight: 700,
              cursor: 'pointer', WebkitTapHighlightColor: 'transparent', minHeight: 44,
            }}
          >
            {compliant
              ? (mode === 'practice' ? 'Done' : 'Roll — depart now')
              : 'Continue'
            }
          </button>
        </div>
      </div>
    );
  }
});

export default HOSPuzzle;
